INSERT IGNORE INTO posts (id, contenu, user_id, user_name, created_at) VALUES
(1,  'Vient de passer ma soutenance PFE avec mention -- merci a tous pour le soutien ! Prochain objectif : trouver un CDI en data science a Tunis.', 15, 'Sami Amara', '2026-05-14 09:42:00'),
(2,  'Rappel : le TP de cryptographie est reporte au jeudi 16 mai. Groupes pairs le matin, groupes impairs apres-midi. Support disponible sur Moodle.', 2, 'Nadia Ayari', '2026-05-14 08:15:00'),
(3,  'Notre startup vient d etre selectionnee pour l incubateur Flat6Labs Tunisia. Recrutement ouvert : 2 dev React/Node.js, 1 designer UX. CV a jobs@mokhtar-labs.tn', 17, 'Mokhtar Saidi', '2026-05-13 17:30:00'),
(4,  'Quelqu un cherche a former un groupe de revision pour les examens ? Je propose un creneau le samedi matin a la bibliotheque. DM si interesse.', 7, 'Amine Ben Salem', '2026-05-13 14:22:00'),
(5,  'Nouveau papier publie : Intrusion Detection in IoT Networks using Graph Neural Networks. Lien dans les commentaires. Retours bienvenus !', 3, 'Hedi Trabelsi', '2026-05-12 11:00:00'),
(6,  'Acme Corp SA recrute ! 2 stages developpement full-stack (React + Spring Boot) pour Juillet-Decembre 2026. Lettre de motivation + CV a hr@acmecorp.tn', 22, 'RH Acme Corp', '2026-05-12 09:00:00'),
(7,  'Disponible pour du mentoring tech : architecture microservices, Docker/K8s, preparation entretiens. 3 creneaux par semaine. Etudiants ESPRIT en priorite.', 19, 'Walid Hosni', '2026-05-11 16:45:00'),
(8,  'Notre projet de fin d etudes (recommandation de jobs par NLP) a remporte le prix du jury lors de la journee PFE ! Tres fier de toute l equipe.', 8, 'Sara Khemiri', '2026-05-11 10:30:00'),
(9,  'Seance de TP Analyse numerique annulee demain. Reportee la semaine prochaine. Les devoirs rendus avant vendredi seront pris en compte.', 4, 'Leila Ben Said', '2026-05-10 20:00:00'),
(10, 'Question : vous utilisez quoi comme librairie pour les graphes en React ? Recharts, Chart.js ou Nivo ? On hesite pour notre projet d integration.', 9, 'Yassine Jbali', '2026-05-10 15:10:00'),
(11, 'Conseil a tous les 4eme annee : preparez votre profil LinkedIn AVANT la soutenance. Les recruteurs vont vous chercher le jour meme.', 21, 'Tarek Nasri', '2026-05-09 12:00:00'),
(12, 'TechVision SARL organise une journee portes ouvertes le 22 mai. Venez decouvrir nos equipes et projets tech. Inscription sur notre site.', 23, 'TechVision SARL', '2026-05-09 09:30:00'),
(13, 'On cherche 2 personnes pour notre equipe au Hackathon IA ESPRIT (7-8 juin). Profil : Python/ML ou backend Spring. DM rapidement !', 11, 'Karim Ferchichi', '2026-05-08 18:20:00'),
(14, 'Bienvenue a tous les etudiants de 1ere annee en GL ! Le premier cours de Structures de Donnees aura lieu vendredi a 10h00, Amphi C. Apportez votre laptop.', 5, 'Faouzi Mbarki', '2026-05-07 08:00:00'),
(15, 'Certifiee AWS Cloud Practitioner apres 3 mois de preparation ! Le guide est gratuit sur le site AWS. N hesitez pas a me demander des conseils.', 14, 'Amal Chebbi', '2026-05-06 21:00:00'),
(16, 'Le Career Center ouvre 40 creneaux de simulation entretien cette semaine. Les 4eme annee et alumni en recherche active sont prioritaires.', 28, 'Anis Karray', '2026-05-14 11:00:00'),
(17, 'Retour terrain: pour un premier poste backend, montrez un projet deploye, des tests et une vraie documentation API. Le code seul ne suffit plus.', 30, 'Sofiene Lahmar', '2026-05-14 10:25:00'),
(18, 'FinTech Lab lance un challenge BI: construire un dashboard risque credit avec SQL et Power BI. Les meilleurs profils seront invites en entretien.', 38, 'Recrutement FinTech Lab', '2026-05-13 16:00:00'),
(19, 'Workshop cybersecurite vendredi: threat modeling, OWASP Top 10 et revue de code securise sur Spring Security.', 25, 'Youssef Mansour', '2026-05-13 13:30:00'),
(20, 'Besoin de volontaires pour accueillir les entreprises pendant la journee portes ouvertes. Inscription aupres du service scolarite.', 27, 'Nour Mejri', '2026-05-12 15:15:00'),
(21, 'Je partage mon template CV junior: une page, projets mesurables, liens GitHub propres et mots-cles adaptes a l offre.', 31, 'Rim Missaoui', '2026-05-12 12:45:00'),
(22, 'Notre equipe cherche encore un profil QA automation pour le PFE. Playwright ou Cypress apprecie, curiosite obligatoire.', 37, 'Talent NovaSoft', '2026-05-11 09:20:00'),
(23, 'Data storytelling: un dashboard utile commence par 3 questions metier, pas par le choix des couleurs.', 26, 'Salma Gharbi', '2026-05-10 17:10:00');
